    // MARK: - QuantumStrength Compatibility

    /// Verifies QuantumStrength raw values match .NET enum
    func testQuantumStrengthDotNetCompatibility() {
        // .NET: Standard=0, Medium=1, Highest=2
        XCTAssertEqual(QuantumStrength.standard.rawValue, 0)
        XCTAssertEqual(QuantumStrength.medium.rawValue, 1)
        XCTAssertEqual(QuantumStrength.highest.rawValue, 2)

        // Should only have 3 values (no Light/Maximum)
        XCTAssertEqual(QuantumStrength.allCases.count, 3)
        XCTAssertNil(QuantumStrength(rawValue: 3)) // No Maximum
    }
}
